            aWandererG = aWandererG ^ (((RotL64(aPrevious, 23U) + aOrbiterG) + RotL64(aOrbiterB, 39U)) + aPhaseAWandererUpdateSaltB[(((31U - aIndex) + 3U)) & 31]);
