            aOrbiterK = (aWandererK + RotL64(aPrevious, 13U)) + 0xE5C4C15F091F1783ULL;
            aOrbiterB = ((aWandererD + RotL64(aScatter, 3U)) + 0x01CEFC501DB8294DULL) + aPhaseAOrbiterAssignSaltE[(((31U - aIndex) + 29U)) & 31];
