            aIngress = aIngress + (RotL64(aOrbiterE, 5U) ^ aOrbiterK);
            aIngress = aIngress + (RotL64(aOrbiterI, 39U) ^ aOrbiterJ);
            aIngress = aIngress + (RotL64(aOrbiterC, 11U) ^ aOrbiterF);
            aIngress = aIngress + RotL64(aOrbiterB, 28U);
            aIngress = TwistMix64::DiffuseC((aIngress + aScatter));
            //
            aWandererG = aWandererG + ((RotL64(aIngress, 3U) + RotL64(aOrbiterA, 39U)) + aOrbiterJ);
            aWandererA = aWandererA ^ ((RotL64(aCross, 22U) + RotL64(aOrbiterH, 24U)) + aOrbiterF);
