            aWandererC = aWandererC ^ ((RotL64(aCross, 35U) + RotL64(aOrbiterF, 60U)) + aOrbiterI);
            aWandererK = aWandererK + (((RotL64(aIngress, 13U) + RotL64(aOrbiterG, 21U)) + aOrbiterH) + aPhaseGWandererUpdateSaltE[((aIndex + 16U)) & 31]);
